const CURRENT_VERSION = '27.0.0'; 
const MIN_SCORE_THRESHOLD = 75; 

// UPDATED BRIDGE CODE WITH SYNC
const BRIDGE_CODE = `const http = require('http');
let signalQueue = [];
let activePositions = [];
let processedIds = new Set(); 
setInterval(() => { processedIds.clear(); }, 60000);

const server = http.createServer((req, res) => {
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') { res.writeHead(204); res.end(); return; }

    if (req.method === 'POST') {
        let body = '';
        req.on('data', chunk => { body += chunk.toString(); });
        req.on('end', () => {
            try {
                const data = JSON.parse(body);
                if (data.type === 'SYNC_STATE') { activePositions = data.positions || []; res.end(JSON.stringify({status:'synced'})); return; }
                if (data.type === 'RESET_BRIDGE') { signalQueue = []; activePositions = []; processedIds.clear(); res.end(JSON.stringify({status: 'cleared'})); return; }
                if (data.type === 'HEARTBEAT') { res.end(JSON.stringify({status: 'ack'})); return; }

                if (data.id && processedIds.has(data.id)) { res.end(JSON.stringify({ status: 'ignored_duplicate' })); return; }
                signalQueue.push(data);
                if (data.id) processedIds.add(data.id);
                res.writeHead(200); res.end(JSON.stringify({ status: 'queued' }));
            } catch (e) { res.writeHead(400); res.end('Invalid JSON'); }
        });
    } else if (req.method === 'GET') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        if (req.url.includes('/signal')) { const sig = signalQueue.shift(); res.end(JSON.stringify(sig || {})); return; }
        if (req.url.includes('/state')) { res.end(JSON.stringify({ positions: activePositions })); return; }
        res.end(JSON.stringify({ status: 'online' }));
    }
});
server.listen(3000, '0.0.0.0', () => { console.log('ARKON BRIDGE v4.0 (SYNC) RUNNING'); });`;

const DEFAULT_CONFIG: AppConfig = {
  telegramBotToken: '',
  telegramChatId: '',
  webhookUrl: 'http://127.0.0.1:3000',
  riskRewardRatio: 2.0, 
  cooldownHours: 2,
  autoExecution: true,
  enableTrailing: true,
  equityProtectionPercent: 5.0, 
  maxAllocationPerTrade: 0.01, 
  maxPyramidingLayers: 3, 
  secureThreshold: 10.0, 
  partialClosePercent: 50.0,
  autoHedgeEnabled: true,
  trailingStepPoints: 200,
  newsBypassMinutes: 30,
  newsCooldownMinutes: 60,
  secureHedgeTrades: false 
};

interface ManagedTrade {
    signalId: string;
    asset: string;
    direction: SignalDirection;
    entryPrice: number;
    currentPrice?: number;
    pnl?: number;
    tp: number;
    sl: number; 
    timestamp: number;
    type: 'ENTRY' | 'HEDGE' | 'FLIP' | 'BOOST';
    ticket?: number;
}

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig>(() => {
    const vCurrent = localStorage.getItem(`arkon_config_v${CURRENT_VERSION}`);
    if (vCurrent) return JSON.parse(vCurrent);
    return DEFAULT_CONFIG;
  });

  const [activeSignals, setActiveSignals] = useState<{[key: string]: TradingSignal}>({});
  const [managedTrades, setManagedTrades] = useState<ManagedTrade[]>([]); // This is now synced from Bridge
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [btcAnalysis, setBtcAnalysis] = useState<MarketAnalysisState | null>(null);
  const [ethAnalysis, setEthAnalysis] = useState<MarketAnalysisState | null>(null);
  const [newsEvents, setNewsEvents] = useState<EconomicEvent[]>([]);
  const [newsGuard, setNewsGuard] = useState<{isPaused: boolean, event?: EconomicEvent, reason: string}>({isPaused: false, reason: 'NORMAL'});

  const [isProcessing, setIsProcessing] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'CONN' | 'NOTIF' | 'PROT' | 'RISK' | 'NEWS' | 'SYSTEM'>('CONN');
  const [viewCode, setViewCode] = useState<'NONE' | 'BRIDGE' | 'MQL5'>('NONE');

  const sendingRef = useRef<Record<string, boolean>>({});
  const sentSignalsRef = useRef<Set<string>>(new Set());
  const cooldownTracker = useRef<Record<string, number>>({});
  const isResetting = useRef(false);

  const addLog = useCallback((message: string, type: LogType = 'INFO', details?: string | object) => {
      setLogs(prev => [{ id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), type, message, details }, ...prev].slice(150)); 
  }, []);

  useEffect(() => {
    if (isResetting.current) return; 
    localStorage.setItem(`arkon_config_v${CURRENT_VERSION}`, JSON.stringify(config));
  }, [config]);

  const handleFactoryReset = () => {
      if(window.confirm("⚠️ تصفير الكأس: هل أنت متأكد من مسح جميع البيانات وإعادة ضبط المصنع؟")) {
          isResetting.current = true;
          localStorage.clear();
          setTimeout(() => { window.location.reload(); }, 100);
      }
  };

  const handleSendSignal = async (signal: TradingSignal, overrideAction?: 'ENTRY' | 'FLIP' | 'HEDGE' | 'BOOST' | 'EXIT' | 'SECURE'): Promise<boolean> => {
    if (!overrideAction && signal.qualityScore < MIN_SCORE_THRESHOLD) return false;
    if (!overrideAction && (sendingRef.current[signal.id] || sentSignalsRef.current.has(signal.id))) return false;

    // Check against SYNCED managedTrades, not local state only
    const assetName = signal.asset.split('-')[0];
    const assetTrades = managedTrades.filter(t => t.asset.includes(assetName));
    const hasOppositeTrade = assetTrades.some(t => t.direction !== signal.direction);
    const isFullCapacity = assetTrades.length >= config.maxPyramidingLayers;

    let actionType: any = overrideAction || 'ENTRY';

    if (!overrideAction && hasOppositeTrade) {
        actionType = config.autoHedgeEnabled ? 'HEDGE' : 'FLIP';
    } else if (!overrideAction && assetTrades.length > 0 && !hasOppositeTrade) {
        if (!isFullCapacity) actionType = 'BOOST';
        else return false; 
    }

    const isDefensive = ['HEDGE', 'FLIP', 'EXIT', 'SECURE'].includes(actionType);

    if (!isDefensive && !overrideAction) {
        const lastExec = cooldownTracker.current[assetName] || 0;
        const hoursDiff = (Date.now() - lastExec) / (1000 * 60 * 60);
        if (hoursDiff < config.cooldownHours) return false; 
    }

    if (actionType === 'ENTRY' || actionType === 'BOOST') {
        const currentTotalLots = managedTrades.length * config.maxAllocationPerTrade;
        if (currentTotalLots + config.maxAllocationPerTrade > config.equityProtectionPercent) {
            if (!sendingRef.current['RISK_BLOCK']) {
                addLog(`Risk Block: Equity Protection Limit Reached`, 'RISK');
                sendingRef.current['RISK_BLOCK'] = true;
                setTimeout(() => sendingRef.current['RISK_BLOCK'] = false, 10000);
            }
            return false;
        }
    }

    if (!isDefensive && newsGuard.isPaused) return false;
    if (!overrideAction) sendingRef.current[signal.id] = true;

    try {
        let adjustedTp = signal.takeProfit;
        if (signal.stopLoss > 0 && config.riskRewardRatio > 0) {
            const riskDistance = Math.abs(signal.entry - signal.stopLoss);
            const rewardDistance = riskDistance * config.riskRewardRatio;
            adjustedTp = signal.direction === SignalDirection.LONG 
                ? signal.entry + rewardDistance 
                : signal.entry - rewardDistance;
            adjustedTp = Math.round(adjustedTp * 100) / 100;
        }

        const payload = {
            ...signal,
            takeProfit: adjustedTp, 
            details: { 
                ...signal.details, 
                secureThreshold: config.secureThreshold, 
                partialClosePercent: config.partialClosePercent, 
                trailingStep: config.trailingStepPoints,
                userRiskReward: config.riskRewardRatio
            }
        };

        const result = await sendToWebhook(payload, config.webhookUrl, 0.0, actionType, config.maxAllocationPerTrade);

        if (result.success) {
            cooldownTracker.current[assetName] = Date.now();

            if (config.telegramBotToken && config.telegramChatId) {
                sendSignalToTelegram(
                    { ...signal, takeProfit: adjustedTp },
                    config.telegramChatId, 
                    config.telegramBotToken, 
                    actionType, 
                    signal.reasoning, 
                    config.webhookUrl
                ).catch(() => {});
            }

            if (!overrideAction) sentSignalsRef.current.add(signal.id);
            // We do NOT update managedTrades here manually anymore. 
            // We rely on the Bridge polling to update the list.
            addLog(`⚡ Signal Sent: ${actionType} ${assetName}`, 'EXEC');
            return true;
        } 
    } catch (err: any) { addLog(`فشل الاتصال بالجسر`, 'ERROR'); }
    finally { if (!overrideAction) sendingRef.current[signal.id] = false; }
    return false;
  };

  const handleManualClose = async (asset: string) => {
