      const trade = managedTrades.find(t => t.asset.includes(asset));
      const exitSignal: TradingSignal = {
          id: `MANUAL-EXIT-${Date.now()}`, timestamp: Date.now(), asset: asset, direction: trade ? trade.direction : SignalDirection.LONG, 
          strength: SignalStrength.STANDARD, entry: 0, stopLoss: 0, tp1: 0, tp2: 0, takeProfit: 0,
          qualityScore: 0, reasoning: "MANUAL_EXIT", gates: [], details: {} as any
      };
      await handleSendSignal(exitSignal, 'EXIT');
