import { TradingSignal, SignalDirection, SignalStrength, DeribitBookSummary, DeribitCandleData, DeribitOrderBook, MarketAnalysisState, LogicGate } from '../types';

// --- ADVANCED QUANT TOOLS ---
const mean = (data: number[]) => data.length === 0 ? 0 : data.reduce((a, b) => a + b, 0) / data.length;
const stdDev = (data: number[]) => {
    if (data.length === 0) return 0;
    const m = mean(data);
    const variance = data.reduce((sum, val) => sum + Math.pow(val - m, 2), 0) / data.length;
    return Math.sqrt(variance);
};

const calculateZScore = (current: number, history: number[]) => {
    const sd = stdDev(history);
    return sd < (current * 0.0001) ? 0 : (current - mean(history)) / sd; // Added floor to prevent infinity
};

const calculateRSI = (prices: number[], period: number = 14): number => {
    if (prices.length < period + 1) return 50;
    let gains = 0, losses = 0;
    for (let i = 1; i <= period; i++) {
        const change = prices[prices.length - i] - prices[prices.length - i - 1];
        if (change >= 0) gains += change;
        else losses -= change;
    }
    const avgGain = gains / period;
    const avgLoss = losses / period;
    if (avgLoss === 0) return 100;
    return 100 - (100 / (1 + (avgGain / avgLoss)));
};

const calculateVWAP = (candles: DeribitCandleData | null): number => {
    if (!candles || candles.close.length === 0) return 0;
    let cumPV = 0, cumV = 0;
    for (let i = 0; i < candles.close.length; i++) {
        const tp = (candles.high[i] + candles.low[i] + candles.close[i]) / 3;
        cumPV += tp * candles.volume[i]; cumV += candles.volume[i];
    }
    return cumV === 0 ? 0 : cumPV / cumV;
};

// Sharpened Hurst for better regime detection
const calculateHurst = (closes: number[]): number => {
    const n = closes.length;
    if (n < 40) return 0.5;
    const m = mean(closes);
    const centered = closes.map(x => x - m);
    const cumDev = [];
    let currentSum = 0;
    for(let val of centered) { currentSum += val; cumDev.push(currentSum); }
    const r = Math.max(...cumDev) - Math.min(...cumDev);
    const s = stdDev(closes);
    if (s === 0 || r === 0) return 0.5;
    return Math.log(r / s) / Math.log(n); // Refined scaling
};

export const generateSignal = (
  asset: 'BTC' | 'ETH',
  summary: DeribitBookSummary,
  allSummaries: DeribitBookSummary[],
  candles: DeribitCandleData | null, 
  dailyCandles: DeribitCandleData | null, 
  orderBook: DeribitOrderBook | null, 
  dvol: number, 
  optionsVolume: number 
): { signal: TradingSignal | null; analysis: MarketAnalysisState } => {

  const price = summary.last || 0;
  const fundingRate = summary.funding_8h || 0;

  const closeHistory = dailyCandles?.close.slice(-50) || []; 
  const hurst = calculateHurst(closeHistory);
  const zScore = calculateZScore(price, closeHistory);
  const rsi = calculateRSI(candles?.close.slice(-30) || [], 14); 
  const vwap = calculateVWAP(candles);
  const vwapDev = vwap > 0 ? ((price - vwap) / vwap) * 100 : 0;

  const volDenominator = candles ? mean(candles.volume.slice(-30)) : 0;
  const volRatio = (candles && volDenominator > 0) ? (mean(candles.volume.slice(-5)) / volDenominator) : 0;

  // --- STRICT REGIME DEFINITION ---
  let regime: 'MEAN_REVERSION' | 'MOMENTUM_TREND' | 'CHOPPY/NOISE' = 'CHOPPY/NOISE';

  // Logic: Momentum requires Hurst > 0.55 AND Volume confirmation
  if (hurst > 0.55 && volRatio > 1.1) {
      regime = 'MOMENTUM_TREND';
  } 
  // Logic: Mean Reversion requires extreme Z-Score but LOW Hurst (Trend exhaustion)
  else if (Math.abs(zScore) > 2.0 && hurst < 0.52) {
      regime = 'MEAN_REVERSION';
  }

  // --- LOGIC GATES ---
  const gates: LogicGate[] = [];
  gates.push({ id: 'regime', name: 'Market Regime', value: regime.replace('_', ' '), threshold: 'Valid Logic', status: regime !== 'CHOPPY/NOISE' ? 'PASS' : 'FAIL', requiredFor: 'ENTRY' });
  gates.push({ id: 'vol', name: 'Volume Surge', value: `${volRatio.toFixed(2)}x`, threshold: '> 1.0', status: volRatio > 1.0 ? 'PASS' : 'FAIL', requiredFor: 'ENTRY' });
  gates.push({ id: 'momentum', name: 'Hurst Exponent', value: hurst.toFixed(2), threshold: '> 0.55 / < 0.52', status: (hurst > 0.55 || (Math.abs(zScore) > 2 && hurst < 0.52)) ? 'PASS' : 'FAIL', requiredFor: 'ENTRY' });
  gates.push({ id: 'safety', name: 'DVOL Limit', value: dvol.toFixed(0), threshold: '< 120', status: dvol < 120 ? 'PASS' : 'FAIL', requiredFor: 'SAFETY' });

  let direction: SignalDirection | null = null;
  let score = 0;

  // STRATEGY EXECUTION
  if (regime === 'MOMENTUM_TREND') {
      if (price > vwap && vwapDev > 0.2) direction = SignalDirection.LONG;
      else if (price < vwap && vwapDev < -0.2) direction = SignalDirection.SHORT;
      score = 60 + (volRatio * 10) + (hurst * 20);
  } 
  else if (regime === 'MEAN_REVERSION') {
      // Contrarian with RSI Confirmation
      if (zScore < -2.2 && rsi < 30) direction = SignalDirection.LONG;
      else if (zScore > 2.2 && rsi > 70) direction = SignalDirection.SHORT;
      score = 70 + (Math.abs(zScore) * 5);
  }

  // Final Blocker Check
  const essentialPass = gates.filter(g => g.requiredFor === 'ENTRY' && g.status === 'PASS').length === 3;
  const finalScore = Math.min(99, Math.round(score * (essentialPass ? 1 : 0.5)));

  const analysis: MarketAnalysisState = {
      asset: summary.instrument_name, price, zScore, vwapDeviation: vwapDev, rSquared: 0, dvol, hurst, rsi, volRatio,
      yearlyHigh: Math.max(...closeHistory), yearlyLow: Math.min(...closeHistory), pricePositionRank: 50, regime, 
      qualityScore: finalScore, gates, 
      primaryBlocker: direction && essentialPass ? "جاهز للتنفيذ ✅" : "جاري تحليل المنطق ⏳", 
      isCooldownActive: false, cooldownRemaining: 0, isCorrelatedBlocked: false,
      liquidityGap: 0, toxicityScore: 0, estimatedSlippage: 0, dataLatencyMs: 0, scoreBreakdown: [],
      dominantFactor: regime, reversalProbability: Math.abs(zScore) * 20,
      trendStrength: hurst * 100, trendDirection: vwapDev > 0 ? 'UP' : 'DOWN',
      fundingRate, openInterest: summary.open_interest || 0, isNewsPaused: false
  };

  if (!direction || !essentialPass) return { signal: null, analysis };

  const targetDistance = price * 0.015; // 1.5% Target
  const tp = direction === SignalDirection.LONG ? price + targetDistance : price - targetDistance;
  const sl = direction === SignalDirection.LONG ? price - (targetDistance / 2) : price + (targetDistance / 2);

  const signalId = `${asset}-${direction}-${Math.floor(Date.now() / 60000)}`;

  const signal: TradingSignal = {
    id: signalId, timestamp: Date.now(), asset: summary.instrument_name, direction,
    strength: finalScore > 85 ? SignalStrength.STRONG : SignalStrength.STANDARD, 
    entry: price, stopLoss: Number(sl.toFixed(2)), tp1: price, tp2: tp, takeProfit: Number(tp.toFixed(2)), 
    qualityScore: finalScore, reasoning: `${regime} | Hurst:${hurst.toFixed(2)} | Z:${zScore.toFixed(1)}`, 
    gates,
    details: { 
        volumeMultiplier: volRatio, fundingRate, correlationScore: 0, zScore, volatilityPremium: 0, 
        statisticalEdge: finalScore, quantRegime: regime, vwap, vwapDeviation: vwapDev, hurstExponent: hurst, rsi
    }
  };

  return { signal, analysis };
};

