    if (!overrideAction && signal.qualityScore < MIN_SCORE_THRESHOLD) return false;
    const assetPure = signal.asset.split('-')[0];
    const assetTrades = managedTrades.filter(t => t.asset.includes(assetPure));
    const hasOppositeTrade = assetTrades.some(t => t.direction !== signal.direction);
    let actionType: any = overrideAction || 'ENTRY';

    if (!overrideAction) {
        if (hasOppositeTrade) {
            actionType = config.autoHedgeEnabled ? 'HEDGE' : 'FLIP';
        } else if (assetTrades.length > 0) {
            if (assetTrades.length < config.maxPyramidingLayers) actionType = 'BOOST';
            else return false;
        }
    }

    if (sendingRef.current[signal.id]) return false;
    sendingRef.current[signal.id] = true;

    try {
        const result = await sendToWebhook(signal, config.webhookUrl, 0.0, actionType, config.maxAllocationPerTrade);
        if (result.success) {
            cooldownTracker.current[assetPure] = Date.now();
