                            </h3>
                            <p className="text-zinc-500 text-xs">التحكم في آلية تنفيذ الأوامر والقيود العامة للمحرك الكمي.</p>
                        </header>
                        <div className="grid grid-cols-1 gap-6">
                             <div className={`p-8 rounded-3xl border transition-all flex items-center justify-between ${config.autoExecution ? 'bg-amber-500/5 border-amber-500/20' : 'bg-zinc-950 border border-zinc-800'}`}>
                                 <div className="max-w-xl">
                                     <h4 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">التنفيذ التلقائي (Auto Pilot)</h4>
                                     <p className="text-xs text-zinc-500">عند التفعيل، سيقوم النظام بإرسال الإشارات التي تتخطى حاجز الجودة ({MIN_SCORE_THRESHOLD}%) فوراً إلى الجسر دون انتظار الموافقة اليدوية.</p>
                                 </div>
                                 <div className="relative inline-block w-16 h-8 cursor-pointer" onClick={() => setConfig({...config, autoExecution: !config.autoExecution})}>
                                     <div className={`absolute inset-0 rounded-full transition-colors ${config.autoExecution ? 'bg-amber-500' : 'bg-zinc-800'}`}></div>
                                     <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-transform ${config.autoExecution ? 'translate-x-8' : 'translate-x-0'}`}></div>
                                 </div>
                             </div>

                             <div className={`p-8 rounded-3xl border transition-all flex items-center justify-between ${config.secureHedgeTrades ? 'bg-indigo-500/5 border-indigo-500/20' : 'bg-zinc-950 border border-zinc-800'}`}>
                                 <div className="max-w-xl">
                                     <h4 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">تأمين الأرباح (Secure Hedge)</h4>
                                     <p className="text-xs text-zinc-500">تحريك وقف الخسارة إلى نقطة الدخول (Break-even) فور وصول السعر لمستوى ربح محدد لتأمين المركز.</p>
                                 </div>
                                 <div className="relative inline-block w-16 h-8 cursor-pointer" onClick={() => setConfig({...config, secureHedgeTrades: !config.secureHedgeTrades})}>
                                     <div className={`absolute inset-0 rounded-full transition-colors ${config.secureHedgeTrades ? 'bg-indigo-500' : 'bg-zinc-800'}`}></div>
                                     <div className={`absolute top-1 left-1 w-6 h-6 bg-white rounded-full transition-transform ${config.secureHedgeTrades ? 'translate-x-8' : 'translate-x-0'}`}></div>
                                 </div>
                             </div>
                        </div>
                    </div>
                )}
             </div>

             {/* Footer Save Button */}
             <div className="absolute bottom-0 left-0 right-0 p-10 bg-gradient-to-t from-black to-transparent pointer-events-none flex justify-end items-center gap-6">
                <span className="text-[10px] text-zinc-600 uppercase font-black tracking-widest">تأكد من حفظ الإعدادات قبل الإغلاق</span>
                <button 
                    onClick={() => setIsSettingsOpen(false)} 
                    className="pointer-events-auto px-16 py-5 bg-white text-black rounded-3xl text-xs font-black uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all"
                >
                    حفظ وإغلاق
                </button>
             </div>
          </div>
        </div>
      )}

      {/* Main App Layout */}
      <header className="flex justify-between items-center mb-8">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 glass-card rounded-2xl flex items-center justify-center border-amber-500/40 bg-zinc-900/50 shadow-lg shadow-amber-500/10">
              <i className="fas fa-cube text-2xl text-amber-500 animate-pulse"></i>
          </div>
          <div>
              <h1 className="text-4xl font-black text-white uppercase tracking-tighter">ARKON <span className="text-amber-500 text-xl font-mono">V{CURRENT_VERSION}</span></h1>
              <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.3em] mt-1">QUANT TRADING TERMINAL | CORE SYSTEM</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
            <div className={`flex items-center gap-2 px-4 py-2 bg-zinc-950 border border-zinc-800 rounded-xl transition-all ${bridgeStatus ? 'border-emerald-500/30' : 'border-rose-500/30'}`}>
                <div className={`w-2 h-2 rounded-full ${bridgeStatus ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]'}`}></div>
                <span className="text-[9px] font-black text-zinc-400 uppercase tracking-widest">
                    {bridgeStatus ? 'BRIDGE ONLINE' : 'BRIDGE OFFLINE'}
                </span>
            </div>
            <button onClick={() => setIsSettingsOpen(true)} className="px-6 py-2.5 bg-zinc-900 border border-zinc-800 rounded-xl font-black text-zinc-400 text-[10px] uppercase hover:bg-white hover:text-black transition-all flex items-center gap-3 shadow-xl">
                الإعدادات <i className="fas fa-cog text-amber-500"></i>
            </button>
        </div>
      </header>

      {/* Main Grid View */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 flex flex-col gap-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <MarketStats state={btcAnalysis} title="BITCOIN" />
                <MarketStats state={ethAnalysis} title="ETHEREUM" />
              </div>
              <div className="h-[400px] shadow-2xl">
                  <TradeLog logs={logs} activeTradesCount={managedTrades.length} managedTrades={managedTrades} onCloseTrade={(a) => {}} />
              </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-8">
              {/* Signal Feed */}
              <div className="flex flex-col gap-4">
                  <h3 className="text-[11px] font-black text-zinc-500 uppercase tracking-[0.4em] mb-2 flex items-center gap-3">
                      <i className="fas fa-broadcast-tower text-amber-500"></i>
                      إشارات السوق الحية
                  </h3>
                  <div className="space-y-4">
                      {Object.values(activeSignals).length === 0 && (
                          <div className="p-10 border border-dashed border-zinc-800 rounded-[2rem] text-center bg-zinc-950/20">
                              <i className="fas fa-search text-zinc-800 text-3xl mb-4"></i>
                              <p className="text-[10px] text-zinc-700 font-black uppercase tracking-widest">في انتظار رصد إشارة كمية...</p>
                          </div>
                      )}
                      {Object.values(activeSignals).map((signal: TradingSignal) => {
                          const isExecuted = managedTrades.some(t => t.asset.includes(signal.asset.split('-')[0]) && t.direction === signal.direction);
                          return (
                            <div key={signal.id} className="animate-in fade-in slide-in-from-bottom duration-500">
                                <SignalCard 
                                    signal={signal} 
                                    onSend={handleSendSignal} 
                                    sending={!!sendingRef.current[signal.id]} 
                                    isActive={isExecuted} 
                                    userRiskCap={100} 
                                />
                            </div>
                          );
                      })}
                  </div>
              </div>

              {/* Exposure Monitor */}
              <div className="glass-card rounded-[2.5rem] p-8 border border-zinc-800 bg-zinc-950/50 min-h-[450px] shadow-2xl">
                  <h3 className="text-xs font-black text-white uppercase tracking-[0.2em] mb-6 border-b border-zinc-800 pb-5 flex justify-between items-center">
                      <span>المراكز المفتوحة (MT5 Sync)</span>
                      <span className="text-[9px] bg-zinc-900 border border-zinc-800 px-3 py-1 rounded-full text-zinc-500 font-mono">LIVE SYNC</span>
                  </h3>
                  <div className="space-y-4 overflow-y-auto max-h-[550px] custom-scrollbar px-1">
                      {managedTrades.length === 0 && (
                          <div className="text-center text-zinc-800 text-[10px] py-16 font-black uppercase tracking-widest">
                              <i className="fas fa-folder-open block text-3xl mb-4 opacity-20"></i>
                              لا يوجد صفقات مفتوحة حالياً
                          </div>
                      )}
                      {managedTrades.map((trade) => (
                          <div key={trade.ticket} className="p-5 rounded-3xl bg-zinc-900 border border-zinc-800 hover:border-zinc-700 transition-all group">
                              <div className="flex justify-between items-center mb-3">
                                  <div className="flex items-center gap-3">
                                      <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs ${trade.direction === SignalDirection.LONG ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
                                          <i className={`fas fa-arrow-${trade.direction === SignalDirection.LONG ? 'up' : 'down'}`}></i>
                                      </div>
                                      <span className="text-sm font-black text-white tracking-tight">{trade.asset.replace('USD','')}</span>
                                      <span className={`text-[9px] font-black px-2 py-0.5 rounded-md ${trade.direction === SignalDirection.LONG ? 'bg-emerald-500 text-black' : 'bg-rose-500 text-black'}`}>
                                          {trade.direction}
                                      </span>
                                  </div>
                                  <span className={`text-sm font-mono font-bold ${trade.pnl && trade.pnl > 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                      {trade.pnl && trade.pnl > 0 ? '+' : ''}${trade.pnl?.toFixed(2)}
                                  </span>
                              </div>
                              <div className="w-full bg-black/40 h-1.5 rounded-full overflow-hidden border border-zinc-800">
                                  <div className={`h-full transition-all duration-1000 ${trade.direction === SignalDirection.LONG ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]' : 'bg-rose-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]'}`} style={{width: '100%'}}></div>
                              </div>
                              <div className="flex justify-between mt-3 text-[9px] font-mono text-zinc-600 uppercase font-black">
                                  <span>Entry: ${trade.entryPrice.toLocaleString()}</span>
                                  <span>TP: ${trade.tp.toLocaleString()}</span>
                              </div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      </div>

      {/* Code Viewer Modal */}
      {viewCode !== 'NONE' && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-10 bg-black/95 backdrop-blur-md animate-in fade-in duration-300">
            <div className="w-full max-w-4xl bg-zinc-900 border border-zinc-800 rounded-[3rem] overflow-hidden flex flex-col h-[85vh] shadow-2xl">
                <div className="p-8 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50">
                    <div>
                        <h3 className="text-white font-black uppercase text-xs tracking-widest mb-1">Source Implementation</h3>
                        <p className="text-[10px] text-zinc-500 font-mono">MODULE: {viewCode === 'BRIDGE' ? 'ARKON_BRIDGE.JS' : 'ARKON_GUARDIAN.MQL5'}</p>
                    </div>
                    <button onClick={() => setViewCode('NONE')} className="w-10 h-10 rounded-full flex items-center justify-center text-zinc-500 hover:text-white hover:bg-white/10 transition-all">
                        <i className="fas fa-times text-xl"></i>
                    </button>
                </div>
                <pre className="flex-1 p-10 overflow-auto font-mono text-[12px] text-zinc-400 bg-[#050507] selection:bg-amber-500/30 selection:text-white custom-scrollbar" dir="ltr">
                    <code>{viewCode === 'BRIDGE' ? BRIDGE_CODE : MQL5_CODE}</code>
                </pre>
                <div className="p-8 bg-zinc-950 border-t border-zinc-800 flex justify-center gap-6">
                    <button 
                        onClick={() => { 
                            navigator.clipboard.writeText(viewCode === 'BRIDGE' ? BRIDGE_CODE : MQL5_CODE); 
                            addLog(`Code ${viewCode} copied to clipboard`, 'SYSTEM'); 
                        }} 
                        className="px-12 py-4 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl hover:scale-105 transition-all"
                    >
                        نسخ الكود البرمجي
                    </button>
                    <button 
                        onClick={() => setViewCode('NONE')} 
                        className="px-12 py-4 bg-zinc-800 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-zinc-700 transition-all"
                    >
                        إغلاق
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default App;
